return await space.current.patchWidget("snake-game", {
  edits: [
    {
      find: /( |[^A-Za-z0-9_])function\s+renderSnake\s*\([^)]*\)\s*\{/,
      replace: "$1function renderSnake(ctx, snake, cellSize, progress, directionMap) {
  const ease = t => 1 - Math.pow(1 - t, 3);
  const p = ease(Math.max(0, Math.min(1, progress ?? 1)));
  ctx.save();
  ctx.fillStyle = snake.color || '#3cb371';
  for (let i = snake.segments.length - 1; i >= 0; i--) {
    const seg = snake.segments[i];
    const prev = snake.prevSegments?.[i] || seg;
    const x = (prev.x + (seg.x - prev.x) * p) * cellSize;
    const y = (prev.y + (seg.y - prev.y) * p) * cellSize;
    const size = cellSize * 0.92;
    const pad = (cellSize - size) / 2;
    const r = Math.max(3, cellSize * 0.22);
    roundRect(ctx, x + pad, y + pad, size, size, r);
    ctx.fill();
  }
  ctx.restore();
}

function roundRect(ctx, x, y, w, h, r) {
  const rr = Math.min(r, w / 2, h / 2);
  ctx.beginPath();
  ctx.moveTo(x + rr, y);
  ctx.arcTo(x + w, y, x + w, y + h, rr);
  ctx.arcTo(x + w, y + h, x, y + h, rr);
  ctx.arcTo(x, y + h, x, y, rr);
  ctx.arcTo(x, y, x + w, y, rr);
  ctx.closePath();
}"
    },
    {
      find: /( |[^A-Za-z0-9_])function\s+gameLoop\s*\([^)]*\)\s*\{/,
      replace: "$1function gameLoop(now) {
  const dt = Math.min(32, now - (state.lastFrame || now));
  state.lastFrame = now;
  state.anim = Math.min(1, (state.anim || 1) + dt / (state.stepMs || 120));
  if (state.anim >= 1 && state.pendingMove) {
    state.snake.prevSegments = state.snake.segments.map(s => ({ ...s }));
    state.snake.segments = state.pendingMove.nextSegments;
    state.pendingMove = null;
    state.anim = 0;
  }
"
    },
    {
      find: /( |[^A-Za-z0-9_])function\s+stepSnake\s*\([^)]*\)\s*\{/,
      replace: "$1function stepSnake() {
  const head = state.snake.segments[0];
  const nextHead = { x: head.x + state.dir.x, y: head.y + state.dir.y };
  const nextSegments = [nextHead, ...state.snake.segments.slice(0, -1)];
  state.pendingMove = { nextSegments };
  state.anim = 0;
}"
    },
    {
      find: /( |[^A-Za-z0-9_])ctx\.clearRect\([^)]*\);\s*renderSnake\s*\(([^)]*)\);/,
      replace: "$1ctx.clearRect(0, 0, canvas.width, canvas.height);
  renderSnake($2, state.anim, state.dir);"
    }
  ]
})

